// ── Top 40 / CHR unified lineage (internal id: TOP40) ─────────────────
// Saves may still contain format:'CHR' until migrateHitsLineage() runs.
const FA_HITS_LATE={'12-17':.88,'18-24':.82,'25-34':.50,'35-49':.20,'50-64':.07,'65+':.02};
function isHitsFormatLineage(fmt){
  return fmt==='TOP40'||fmt==='CHR';
}
function canonicalHitsFormatKey(fmt){
  return fmt==='CHR'?'TOP40':fmt;
}
function hitsLineageAxisBlendT(year){
  return _smoothstep(1978,1992,year||1970);
}
function hitsFormatSurfaceLabel(year){
  const t=hitsLineageAxisBlendT(year||1970);
  if(t<0.28)return 'Top 40';
  return 'CHR';
}
/** First calendar year where the hits lineage surface label is CHR (was Top 40 the year before). */
function hitsLineageFirstChrCalendarYear(){
  for(let y=1971;y<=2030;y++){
    if(hitsFormatSurfaceLabel(y)==='CHR'&&hitsFormatSurfaceLabel(y-1)==='Top 40')return y;
  }
  return null;
}
function fmtLabel(fmt,yearOpt){
  if(!fmt)return '';
  if(isHitsFormatLineage(fmt)){
    const y=yearOpt!==undefined&&yearOpt!==null?yearOpt:(typeof G!=='undefined'&&G?G.year:1970);
    return hitsFormatSurfaceLabel(y);
  }
  return FM[fmt]?.l||fmt;
}
function driftDefKey(fmt){
  return isHitsFormatLineage(fmt)?'TOP40':fmt;
}
function hitsDriftStoreKey(fmt){
  return isHitsFormatLineage(fmt)?'TOP40':fmt;
}
function hitsDriftPolesForYear(year){
  const y=year||1970;
  // Year bands (not axisBlendT): mid-80s stays rock-anchored; full CHR poles only from ~1989.
  if(y>=1989){
    return {
      poleA:{name:'Pure Pop Hits',desc:'Maximum mainstream appeal, 12–24 focus. Peak CHR ceiling.'},
      poleB:{name:'Rhythmic Edge',desc:'Hip-hop and R&B-influenced pop; holds better through trend shocks.'},
    };
  }
  if(y>=1983){
    return {
      poleA:{name:'Pop Hits',desc:'Mass-appeal chart pop and MTV-era hits; still fighting rock for 18–34 ears.'},
      poleB:{name:'Rock / Rhythmic Edge',desc:'Guitar-driven hits and album-rock credibility; R&B and crossover starting to thread in — rhythmic is emerging, not dominant.'},
    };
  }
  return {
    poleA:{name:'Bubblegum Pop',desc:'Pure hits, youngest demos; broad, personality-heavy Top 40.'},
    poleB:{name:'Rock Edge',desc:'Credibility with 18–34; holds better when rock surges.'},
  };
}
function hitsTop40DemoEffect(drift,coh,year){
  const lean=_clamp01(drift/100);
  const y=year||1970;
  // Early: left = teen/mass pop; right = 18–34 rock (not hotter teens than bubblegum).
  const early={
    '12-17':(1-lean)*.22+lean*.02,
    '18-24':(1-lean)*.10+lean*.14,
    '25-34':(1-lean)*.03+lean*.10,
    '35-49':lean*.04,
  };
  // Transitional (~1983–88): same axis idea as poles — pop left, rock-anchored right with slight rhythmic pull.
  const trans={
    '12-17':(1-lean)*.18+lean*.05,
    '18-24':(1-lean)*.08+lean*.12,
    '25-34':(1-lean)*.04+lean*.10,
    '35-49':(1-lean)*.02+lean*.06,
  };
  const late={
    '12-17':(1-lean)*.18,
    '18-24':lean*.12,
    '25-34':lean*.10,
    '35-49':(1-lean)*.04,
  };
  let bonus=0;
  if(y<1982){
    bonus=early[coh]||0;
  }else if(y<1989){
    const bt=_smoothstep(1982,1984,y);
    bonus=(early[coh]||0)*(1-bt)+(trans[coh]||0)*bt;
  }else{
    const t=hitsLineageAxisBlendT(y);
    bonus=(trans[coh]||0)*(1-t)+(late[coh]||0)*t;
  }
  return Math.max(0.5,1+bonus);
}
function migrateHitsLineage(G){
  if(!G)return;
  (G.stations||[]).forEach(s=>{
    if(!s||s._bpSlotDeferred)return;
    if(s.format==='CHR')s.format='TOP40';
    if(s.drift){
      if(s.drift.CHR!==undefined&&s.drift.TOP40===undefined)s.drift.TOP40=s.drift.CHR;
      delete s.drift.CHR;
    }
    if(s.driftHistory&&s.driftHistory.CHR){
      if(!s.driftHistory.TOP40)s.driftHistory.TOP40=s.driftHistory.CHR;
      delete s.driftHistory.CHR;
    }
  });
  if(Array.isArray(G.unlockedFormats))
    G.unlockedFormats=G.unlockedFormats.filter(f=>f!=='CHR');
  const mergeTalentFit=ff=>{
    if(!ff||typeof ff!=='object')return;
    if(ff.CHR!=null&&ff.TOP40==null)ff.TOP40=ff.CHR;
    delete ff.CHR;
  };
  (G.talentBench||[]).forEach(ent=>mergeTalentFit(ent?.talent?.formatFit));
  (G.stations||[]).forEach(s=>{
    if(!s?.prog)return;
    Object.values(s.prog).forEach(sd=>mergeTalentFit(sd?.talent?.formatFit));
  });
}
const SW={morningDrive:.38,afternoonDrive:.26,midday:.18,evening:.11,overnight:.07};
const SL={morningDrive:'MORNING',afternoonDrive:'AFTERNOON',midday:'MIDDAY',evening:'EVENING',overnight:'OVERNIGHT'};
const TALK_FMTS=['NEWS_TALK','SPORTS_TALK','PODCAST_TALK','ALL_NEWS'];
// Light market × format monetization (Duncan-style calibration). Revenue only; ±~10% max.
// Keys = G.marketId for top-3 metros; omit format → 1. Does not affect shares.
const MARKET_FMT_ADJ={
  newyork:{
    NEWS_TALK:1.05,SPORTS_TALK:1.04,
    URBAN_CONTEMP:0.90,RHYTHMIC:0.90,SOUL_RNB:0.92,
  },
  losangeles:{
    SPANISH:1.08,NEWS_TALK:0.95,URBAN_CONTEMP:0.94,
  },
  chicago:{
    NEWS_TALK:1.08,SPORTS_TALK:1.06,URBAN_CONTEMP:0.95,RHYTHMIC:0.96,
  },
};
function marketFormatMonMult(marketId,format){
  const v=MARKET_FMT_ADJ[marketId]?.[format];
  return typeof v==='number'&&v>0?v:1;
}
/** Share-based sell-through of spot inventory (rating points 0–100). Revenue only; does not affect shares. */
function getSelloutRate(sharePct){
  if(sharePct<1)return 0.35;
  if(sharePct<2)return 0.50;
  if(sharePct<4)return 0.65;
  if(sharePct<6)return 0.75;
  if(sharePct<10)return 0.85;
  if(sharePct<15)return 0.92;
  return 0.98;
}
/** Unweighted mean of cohort CPM — soft anchor for early-era reach blending (does not replace demo CPM). */
function neutralCpmMean(){
  return COH.reduce((sum,c)=>sum+(CPM[c]||0),0)/Math.max(1,COH.length);
}
/**
 * Pre-1986: for market leaders / near-leaders, blend book CPM slightly toward demo-neutral
 * so stacked demo × format premiums do not crush a #1 station (1970s buyers still chased gross reach).
 */
function earlyEraWcpmReachBlend(s,G,wcpm,year,fmd,podBonus,gcpm){
  if(year>=1986||!G?.stations)return wcpm;
  const comm=[...G.stations].filter(st=>st&&!st._bpSlotDeferred&&!st.isPublic)
    .sort((a,b)=>(b.rat?.share||0)-(a.rat?.share||0));
  if(comm.length<2)return wcpm;
  const idx=comm.findIndex(st=>st.id===s.id);
  if(idx>1)return wcpm;
  const shr=s.rat?.share||0;
  if(shr<0.092)return wcpm;
  if(idx===1){
    const leader=comm[0]?.rat?.share||0;
    if(leader-shr>0.045)return wcpm;
  }
  const wcpmNeutral=neutralCpmMean()*(fmd.cpm||1)*(1+(fmd.ab||0))*podBonus*gcpm;
  const eraFade=year<=1970?1:Math.max(0,1-(year-1970)/16);
  const shareK=Math.max(0,Math.min(1,(shr-0.092)/0.095));
  const rankW=idx===0?1:0.42;
  let b=0.13*eraFade*shareK*rankW;
  // AM Top 40: less CPM "reach insurance" for near-leaders — buyers still chased hits, but the lane stayed contestable.
  if(year<1986&&s.format==='TOP40'&&s.sig?.type==='AM'){
    b*=Math.max(0.48,1-0.52*_smoothstep(1971,1980,year));
  }
  return wcpm*(1-b)+wcpmNeutral*b;
}
/**
 * Pre-1986: top-two share stations retain meaningful billing vs stacked weak-signal / format penalties.
 * Extra nudge for small-power AM music #1 — local retail still bought the station that won the diary.
 */
function earlyEraDominantAudienceMonMult(s,G,year){
  if(year>=1986||!G?.stations)return 1;
  const comm=[...G.stations].filter(st=>st&&!st._bpSlotDeferred&&!st.isPublic)
    .sort((a,b)=>(b.rat?.share||0)-(a.rat?.share||0));
  if(comm.length<2)return 1;
  const idx=comm.findIndex(st=>st.id===s.id);
  if(idx>1)return 1;
  const shr=s.rat?.share||0;
  if(shr<0.086)return 1;
  if(idx===1){
    const leader=comm[0]?.rat?.share||0;
    if(leader-shr>0.048)return 1;
  }
  const eraFade=year<=1970?1:Math.max(0,1-(year-1970)/16);
  const shareK=Math.max(0,Math.min(1,(shr-0.086)/0.095));
  let rankW=idx===0?1:0.48;
  let mult=1+0.24*eraFade*shareK*rankW;
  if(s.sig?.type==='AM'&&!TALK_FMTS.includes(s.format)&&idx===0&&['1kw','5kw','10kw'].includes(s.sig?.pw)){
    mult+=0.07*eraFade*shareK;
  }
  mult=Math.min(1.32,mult);
  // AM Top 40 leadership still bills well, but the model had stacked "small AM #1" comfort — taper toward late-70s / early-80s fragility.
  if(year<1986&&s.format==='TOP40'&&s.sig?.type==='AM'){
    const frag=_smoothstep(1972,1982,year)*(0.44+0.44*shareK);
    mult=1+(mult-1)*Math.max(0.36,1-frag);
  }
  return mult;
}
function fmEarlyEraBaseMult(year){
  if(year<1973)return 0.68;
  if(year<1976)return 0.75;
  if(year<1980)return 0.82;
  if(year<1983)return 0.90;
  if(year<1986)return 0.96;
  return 1.00;
}
function fmEarlyEraMarketAdj(marketId){
  const tier=(MARKETS[marketId]||{}).rankTier||'medium';
  // Mega: keep early-FM challenging but aligned with prior ~0.9× monetization in top markets (base 0.68 alone was too harsh vs playtests).
  if(tier==='mega')return 0.22;
  if(tier==='large')return 0.03;
  if(tier==='medium')return 0.01;
  return 0.00;
}
function fmEarlyEraMult(year,marketId){
  return Math.min(1.0,fmEarlyEraBaseMult(year)+fmEarlyEraMarketAdj(marketId));
}
/** Extra FM music lift outside mega markets (leaner rep firms still moved spots on local FM). Revenue only. */
function fmEarlyEraSecondaryFmLift(marketId){
  const tier=(MARKETS[marketId]||{}).rankTier||'medium';
  if(tier==='mega')return 0;
  if(tier==='large')return 0.06;
  if(tier==='medium')return 0.12;
  return 0.14;
}
function earlyEraSmallMarketOpsRelief(year,marketId){
  const tier=(MARKETS[marketId]||{}).rankTier||'medium';
  if(year>=1980)return 1.0;
  if(tier==='mega')return 1.0;
  if(tier==='large')return 0.92;
  if(tier==='medium')return 0.82;
  return 0.78;
}
/** FCC/regulatory + corporate overhead floor — leaner in 1970s secondary markets than mega (pre-1980 only). */
function earlyEraSmallMarketRegRelief(year,marketId){
  const tier=(MARKETS[marketId]||{}).rankTier||'medium';
  if(year>=1980)return 1.0;
  if(tier==='mega')return 1.0;
  if(tier==='large')return 0.94;
  if(tier==='medium')return 0.88;
  return 0.84;
}
function earlyEraAmTalkSmallMarketSupport(format,year,marketId,sigType){
  if(sigType!=='AM')return 1.0;
  if(!['NEWS_TALK','SPORTS_TALK'].includes(format))return 1.0;
  if(year>=1980)return 1.0;
  const tier=(MARKETS[marketId]||{}).rankTier||'medium';
  if(tier==='mega')return 1.00;
  if(tier==='large')return 1.06;
  if(tier==='medium')return 1.18;
  return 1.14;
}
// Community identity potential by format (0–1 scale)
// Formats with deep cultural roots build identity faster and lose it harder
const COMMUNITY_IDENTITY={
  SOUL_RNB:1.0,      // Highest — cultural institution, civil rights legacy
  GOSPEL:0.95,       // Church community, intensely personal loyalty
  COUNTRY:0.85,      // Rural/Southern identity, deeply tribal
  SPANISH:0.90,      // Immigrant community anchor, irreplaceable
  NEWS_TALK:0.70,    // Civic institution, opinion leader status
  ALL_NEWS:0.68,     // Institutional news brand; less "voice" than opinion talk
  SPORTS_TALK:0.65,  // Fan community hub
  ADULT_STANDARDS:0.75, // Nostalgic, older community cornerstone
  MOR:0.55,          // Broad but shallow — friendly to everyone, vital to no one
  ALBUM_ROCK:0.60,   // Subculture identity, loyal but not civic
  CLASSIC_ROCK:0.65, // Generational identity — "the station I grew up with"
  ALT_ROCK:0.55,     // Scene credibility, younger and more fickle
  URBAN_CONTEMP:0.75,// Youth community, cultural tastemaker
  ADULT_CONTEMP:0.40,// Demographically broad = identity-thin
  HOT_AC:0.35,
  TOP40:0.28,       // Unified hits format: mass reach, moderate roots vs soul/country
  BEAUTIFUL_MUSIC:0.45,
  OLDIES:0.60,       // "This is the station my dad listened to"
  CLASSIC_HITS:0.55,
  PODCAST_TALK:0.35,
};

const MUSIC_FMTS=['TOP40','COUNTRY','SOUL_RNB','MOR','ADULT_STANDARDS','ALBUM_ROCK','BEAUTIFUL_MUSIC',
  'CLASSIC_ROCK','ADULT_CONTEMP','URBAN_CONTEMP','ALT_ROCK','RHYTHMIC','HOT_AC','CLASSIC_HITS','OLDIES','GOSPEL','SPANISH'];
function vacantLabel(fmt,slot,s){
  const isTalk=TALK_FMTS.includes(fmt);
  if(s&&typeof G!=='undefined'&&G){
    const f=getStationFranchise(s,slot,G);
    if(f)return `"${f.name}"`;
  }
  // Overnight is always automation or paid programming regardless of format
  if(slot==='overnight')return isTalk?'PAID PROGRAMMING':'AUTOMATION';
  if(slot==='evening')return isTalk?'NATIONAL SHOW':'AUTOMATION';
  // Prime dayparts: the distinction matters most
  if(isTalk)return 'NATIONAL SHOW';
  return 'AUTOMATION';
}
/** Chronological display order: Morning → Midday → Afternoon → Evening → Overnight (do not use object iteration for UI). */
const DAYPART_SLOTS=['morningDrive','midday','afternoonDrive','evening','overnight'];
/** Market-wide superstar talent — prior 80/60/5y gates rarely fired by 1980 in normal play; tuned so 0–2 stars can emerge late 70s without trivializing. */
const SUPERSTAR={
  RAW_QUALITY_MIN:55,
  QUALITY_THRESHOLD:75,
  TENURE_THRESHOLD:3,
  MAX_PER_MARKET:2,
  EFF_Q_MULT:1.40,
  OQ_BONUS:8,
  SHARE_BOOST_ON_ARRIVE:0.008,
  SHARE_LOSS_ON_DEPART:0.006,
  SALARY_FLOOR_BASE:55000,
  SALARY_CAP_MULT_BONUS:0.50,
  POACH_RESIST_BONUS:0.30,
};
const SUPERSTAR_DAYPART_ORDER={morningDrive:0,midday:1,afternoonDrive:2,evening:3,overnight:4};

/** Effective daypart quality for station OQ weighting — superstars lift slot contribution (capped at 100). */
function effSlotQForOq(sd){
  let q=sd?.quality||20;
  if(sd?.talent && (sd.talent._suspended||0)>0){
    return Math.max(12,Math.round(q*0.48));
  }
  if(sd?.talent?.superstar===true){
    q=Math.min(100,q*SUPERSTAR.EFF_Q_MULT);
  }
  return q;
}
function slotQualityForOQ(s,sl,G){
  const f=getStationFranchise(s,sl,G);
  if(f)return f.quality;
  return effSlotQForOq(s.prog?.[sl]);
}
function refreshStationOQ(s,G){
  if(!s||s._bpSlotDeferred)return;
  const sup=Object.values(s.prog||{}).some(sd=>sd?.talent?.superstar)?SUPERSTAR.OQ_BONUS:0;
  s.oq=Math.round(Object.entries(SW).reduce((sum,[sl,w])=>sum+slotQualityForOQ(s,sl,G)*w,0)+sup);
}
function refreshAllStationOQ(G){
  (G.stations||[]).forEach(s=>refreshStationOQ(s,G));
}

// ── TALENT TROUBLE (Phase 1: FCC / sponsor / DUI decision events) ─
