function franchiseFormatFit(franchise,fmt){
  return franchise.formats.includes(fmt)?1.0:0;
}
function initFranchiseRights(G){
  if(!G.franchiseRights)G.franchiseRights={};
  NATIONAL_FRANCHISES.forEach(f=>{
    if(G.year<f.introduced)return;
    if(G.franchiseRights[f.id])return;
    let holderId=null,holderName='—';
    const newlyIntroduced=G.year===f.introduced;
    if(f.exclusive&&!newlyIntroduced){
      const eligible=G.stations.filter(s=>!s.isPlayer&&!s.isPublic&&f.formats.includes(s.format));
      if(eligible.length&&Math.random()<0.6){
        const holder=eligible[Math.floor(Math.random()*eligible.length)];
        holderId=holder.id;holderName=holder.callLetters;
      }
    }
    G.franchiseRights[f.id]={
      holderId,holderName,
      fee:Math.round(f.baseFee*(0.8+Math.random()*0.4)/1000)*1000,
      contractEnd:newlyIntroduced?G.year:G.year+f.contractYrs+Math.floor(Math.random()*2),
      bids:{},auctionOpen:false,auctionCloses:null,relationship:{},
    };
  });
}
function getStationFranchise(s,slot,G){
  if(!G.franchiseRights)return null;
  return NATIONAL_FRANCHISES.find(f=>{
    if(f.slot!==slot)return false;
    const r=G.franchiseRights[f.id];
    if(!r?.holderId)return false;
    return syndicationHaloAppliesToStation(s,r.holderId,G);
  })||null;
}
/** National syndication covers this daypart for this station — no parallel local show (hire/move) unless a benched host is reassigned via franchise tools. */
function franchiseSlotBlocksNewLocalTalent(s,slot,G){
  return !!(getStationFranchise(s,slot,G)&&!s?.prog?.[slot]?.talent);
}
/** When franchise rights land on a new holder, any local host already in that daypart must leave the air (player → bench; AI → released). */
function benchLocalHostDisplacedByFranchiseWin(station,franchise,G){
  if(!station?.prog||!franchise)return;
  const slot=franchise.slot;
  const sd=station.prog[slot];
  if(!sd?.talent)return;
  const nm=sd.talent.name;
  if(station.isPlayer&&mpIsMe(station)){
    if(removeTalentToBenchInternal(station.id,slot)){
      G.news.unshift({v:'MEDIUM',
        t:`📻 "${franchise.name}" now programs ${SL[slot]} on ${station.callLetters} — ${nm} moved to your talent bench. Reassign from Manage Talent or National Franchises.`,
        y:G.year,p:G.period,iy:true});
      logHistory(station,'TALENT',`Benched ${nm} — ${SL[slot]} (displaced by "${franchise.name}")`,G);
    }
  } else {
    sd.talent=null;
    sd.quality=Math.max(10,Math.round((sd.quality||20)*0.72));
    refreshStationOQ(station,G);
  }
}
function applyFranchiseToSlot(s,slot,G){
  const f=getStationFranchise(s,slot,G);
  if(!f)return null;
  return{franchise:f,quality:f.quality,name:f.name};
}
function franchiseDemoMult(s,coh,G){
  let m=1;
  if(!G?.franchiseRights)return m;
  NATIONAL_FRANCHISES.forEach(f=>{
    if(G.year<f.introduced)return;
    const r=G.franchiseRights[f.id];
    if(!r?.holderId||!syndicationHaloAppliesToStation(s,r.holderId,G))return;
    const b=f.demoBoost?.[coh];
    if(b)m*=1+b;
  });
  return m;
}
function syndicationFeesForStation(s,G){
  let fee=0;
  const mkt=MARKETS[G.marketId||'atlanta']||MARKETS.atlanta;
  (mkt.teams||[]).forEach(team=>{
    const r=G.sportsRights?.[team.id];
    if(r?.holderId===s.id)fee+=Math.round((r.fee||0)/2);
  });
  NATIONAL_FRANCHISES.forEach(f=>{
    const r=G.franchiseRights?.[f.id];
    if(r?.holderId===s.id)fee+=Math.round((r.fee||0)/2);
  });
  return fee;
}
function runFranchiseEvents(G){
  if(!G.franchiseRights)return[];
  initFranchiseRights(G);
  const acts=[];
  NATIONAL_FRANCHISES.forEach(f=>{
    if(G.year<f.introduced)return;
    const r=G.franchiseRights[f.id];
    if(!r)return;
    if(r.contractEnd===G.year&&G.period===1&&!r.auctionOpen){
      r.auctionOpen=true;r.auctionCloses=G.year;r.bids={};
      acts.push({v:'HIGH',
        t:`📻 "${f.name}" franchise available — bidding opens for market exclusivity. ${r.holderId?'Current holder: '+r.holderName+'.':'Currently unowned.'}`,
        y:G.year,p:G.period});
    }
    if(r.auctionOpen&&shouldResolveRightsAuction(G,r.auctionCloses)){
      resolveFranchiseAuction(f,r,G,acts);
    }
  });
  return acts;
}
function resolveFranchiseAuction(franchise,rights,G,acts){
  const _aiBidProb=franchise.exclusive?0.65:0.40;
  G.stations.filter(s=>!s.isPlayer&&!s.isPublic&&franchise.formats.includes(s.format)).forEach(s=>{
    const fmtOk=franchiseFormatFit(franchise,s.format)>=1;
    const cashStress=(s.fin?.ebitda||0)<-(s.fin?.rev||1)*0.3;
    if(cashStress&&Math.random()>0.2)return;
    if(!fmtOk)return;
    if(Math.random()>_aiBidProb)return;
    const rel=(rights.relationship?.[s.id]||0);
    const slotPrem={morningDrive:1.15,midday:1.05,afternoonDrive:1.12,evening:1.0,overnight:0.92}[franchise.slot]||1;
    const aiBid=Math.round(franchise.baseFee*slotPrem*(0.85+Math.random()*0.70+rel*0.003)/1000)*1000;
    if(!rights.bids[s.id]||rights.bids[s.id]<aiBid)rights.bids[s.id]=aiBid;
  });
  if(!Object.keys(rights.bids).length){
    if(franchise.exclusive){
      const eligible=G.stations.filter(s=>!s.isPlayer&&!s.isPublic&&franchise.formats.includes(s.format));
      if(eligible.length){
        const fallback=eligible[Math.floor(Math.random()*eligible.length)];
        rights.holderId=fallback.id;rights.holderName=fallback.callLetters;
        rights.fee=Math.round(franchise.baseFee*0.75/1000)*1000;
        rights.contractEnd=G.year+franchise.contractYrs;
        rights.auctionOpen=false;
        acts.push({v:'LOW',t:`📻 "${franchise.name}" picked up by ${fallback.callLetters} — $${Math.round(rights.fee/1000)}K/yr (no auction).`,y:G.year,p:G.period});
        benchLocalHostDisplacedByFranchiseWin(fallback,franchise,G);
        return;
      }
    }else if(rights.holderId){
      rights.contractEnd=G.year+franchise.contractYrs;
      acts.push({v:'LOW',t:`📻 "${franchise.name}" retained by ${rights.holderName} — no competing bids.`,y:G.year,p:G.period});
    }
    rights.auctionOpen=false;
    return;
  }
  let winner=null,winnerBid=0,winnerEff=0;
  Object.entries(rights.bids).forEach(([sid,bid])=>{
    const stn=G.stations.find(st=>st.id===sid);if(!stn)return;
    const rel=(rights.relationship?.[sid]||0)/100;
    const incumbent=sid===rights.holderId?0.15:0;
    const fmt=franchiseFormatFit(franchise,stn.format);
    const effBid=bid*(1+rel*0.20+incumbent)*(0.65+0.35*fmt);
    if(effBid>winnerEff){winner=stn;winnerBid=bid;winnerEff=effBid;}
  });
  if(!winner){
    rights.auctionOpen=false;
    rights.bids={};
    if(rights.holderId){
      rights.contractEnd=G.year+franchise.contractYrs;
      acts.push({v:'LOW',t:`📻 "${franchise.name}" — no valid winning bid; ${rights.holderName||'holder'} retained.`,y:G.year,p:G.period});
    }
    return;
  }
  const prev=rights.holderId?G.stations.find(st=>st.id===rights.holderId):null;
  if(!rights.relationship)rights.relationship={};
  rights.relationship[winner.id]=Math.min(100,(rights.relationship[winner.id]||0)+25);
  if(winner.isPlayer){
    const pid=winner._mpOwner!==undefined?winner._mpOwner:null;
    if(pid!==null&&G._playerCash){
      G._playerCash[pid]=(G._playerCash[pid]||0)-winnerBid*2;
      if(MP.playerId===pid)G.cash=G._playerCash[pid];
    }else G.cash-=winnerBid*2;
    if(MP.mode==='live')MP.emit('player_cash_update',{playerId:pid??MP.playerId,cash:G._playerCash?.[pid??MP.playerId]??G.cash});
  }
  let frMp;
  if(MP.mode==='live'){
    frMp=[];
    if(winner.isPlayer&&winner._mpOwner!==undefined)frMp.push(winner._mpOwner);
    if(prev&&prev.isPlayer&&prev._mpOwner!==undefined&&(!winner.isPlayer||prev._mpOwner!==winner._mpOwner))frMp.push(prev._mpOwner);
  }
  if(franchise.exclusive&&prev&&prev.id!==winner.id){
    acts.push({v:prev.isPlayer?'HIGH':'LOW',
      t:`📻 "${franchise.name}" moves from ${prev.callLetters} to ${winner.callLetters} — ${f$(winnerBid)}/yr.`,
      y:G.year,p:G.period,iy:prev.isPlayer||winner.isPlayer,
      mpForPids:frMp&&frMp.length?frMp:undefined});
  }else{
    acts.push({v:winner.isPlayer?'HIGH':'LOW',
      t:`📻 "${franchise.name}" secured by ${winner.callLetters} — ${f$(winnerBid)}/yr for ${franchise.contractYrs} years.`,
      y:G.year,p:G.period,iy:winner.isPlayer,
      mpForPids:frMp&&frMp.length?frMp:undefined});
  }
  if(prev&&prev.id!==winner.id&&prev.isPlayer){
    Object.values(prev.mom||{}).forEach(m=>{if(m)m.tgt=Math.max(0.001,m.tgt-0.004);});
  }
  const prevHolderId=prev?.id??null;
  rights.holderId=winner.id;
  rights.holderName=winner.callLetters;
  rights.fee=winnerBid;
  rights.contractEnd=G.year+franchise.contractYrs;
  rights.auctionOpen=false;
  rights.bids={};
  if(prevHolderId!==winner.id)benchLocalHostDisplacedByFranchiseWin(winner,franchise,G);
}
function placeFranchiseBid(franchiseId,stationId,amount){
  if(!G.franchiseRights?.[franchiseId])return;
  const r=G.franchiseRights[franchiseId];
  if(!r.auctionOpen){showToast('Bidding not currently open for this franchise.','warn');return;}
  const f=NATIONAL_FRANCHISES.find(fr=>fr.id===franchiseId);
  if(!f)return;
  r.bids[stationId]=amount;
  const stn=G.stations.find(x=>x.id===stationId);
  const _fpid=stn?._mpOwner;
  G.news.unshift({v:'LOW',t:`📻 Bid submitted for "${f.name}" franchise — ${f$(amount)}/yr.`,y:G.year,p:G.period,iy:true,
    mpForPids:MP.mode==='live'&&_fpid!==undefined?[_fpid]:undefined});
  MP.action('franchise_bid',{franchiseId,stationId,amount});
  showToast(`Bid of ${f$(amount)}/yr submitted for "${f.name}".`,'info');
  openFranchise(stationId);
  renderAll();
}

function triggerFranchiseTrouble(G){
  const acts=[];
  if(!G.franchiseRights||G.pendingDecisionEvent)return acts;
  for(const f of NATIONAL_FRANCHISES){
    if(f.troubleMod<=1.0)continue;
    const r=G.franchiseRights[f.id];
    if(!r?.holderId)continue;
    const holder=G.stations.find(st=>st.id===r.holderId);
    if(!holder||!holder.isPlayer)continue;
    const prob=0.015*f.troubleMod;
    if(Math.random()>prob)continue;
    const pool=f.id==='wild_card'
      ?['fcc_language','fcc_indecency','sponsor_boycott']
      :['sponsor_boycott','fcc_indecency'];
    const scId=pool[Math.floor(Math.random()*pool.length)];
    const sc=TROUBLE_SCENARIOS.find(s=>s.id===scId);
    if(!sc)continue;
    G.pendingDecisionEvent={
      isFranchise:true,franchiseId:f.id,
      scenarioId:scId,stationId:holder.id,slot:f.slot,
      talentName:`"${f.name}" (national franchise)`,
      rivalStation:'',year:G.year,period:G.period,
      ownerId:holder._mpOwner!==undefined?holder._mpOwner:0,
    };
    acts.push({v:'HIGH',
      t:`⚠ INCIDENT: ${sc.title} — "${f.name}" at ${holder.callLetters}. Decision required.`,
      y:G.year,p:G.period,iy:true});
    break;
  }
  return acts;
}

// ══════════════════════════════════════════════════════════════════
// MULTIPLAYER STUB — Socket.io integration points
// Single-player: MP.mode='solo', all actions execute locally
// Multiplayer: MP.mode='live', actions emit to server, state arrives via socket
// ══════════════════════════════════════════════════════════════════
// ══════════════════════════════════════════════════════════════════
// MULTIPLAYER SYSTEM
// ══════════════════════════════════════════════════════════════════
const MP = {
  mode: 'solo',       // 'solo' | 'live'
  playerId: null,     // 0=host, 1-3=guests (numeric index in players array)
  socketId: null,     // this socket's id
  roomId: null,
  socket: null,
  isHost: false,
  players: [],        // [{socketId, name, playerId, ready, connected}]
  commitLog: {},      // {socketId: bool}
  _chatOpen: false,
  _unreadChat: 0,

  // ── emit to server ──────────────────────────────────────────────
  emit(event, payload) {
    if (this.mode !== 'live' || !this.socket) return;
    this.socket.emit(event, { roomId: this.roomId, ...payload });
  },
  /** Emit with Socket.io acknowledgement (server must invoke the callback). */
  emitAck(event, payload, onAck) {
    if (this.mode !== 'live' || !this.socket) return;
    this.socket.emit(event, { roomId: this.roomId, ...payload }, onAck);
  },

  // ── broadcast player action ─────────────────────────────────────
  // Call this from every do*() function that mutates G.
  // In solo: no-op. In live: tells server (and other clients) what happened.
  action(action, payload) {
    if (this.mode !== 'live') return;
    if (G && G._mpBankrupt && G._mpBankrupt[MP.playerId]) return;
    if (G && G.mpPhase === 'endgame' && action !== 'mp_continue') return;
    // Host includes current G so server can persist mid-period state on every action.
    // This ensures rejoiners get settings like progBudget, salesForce, etc.
    this.emit('player_action', { action, payload, G: this.isHost ? G : undefined });
  },

  // ── handle incoming action from another player ──────────────────
  applyRemoteAction(envelope) {
    const { action, payload, playerId } = envelope;
    // Remote actions are applied directly — no UI modal flow needed.
    // Merge playerId into payload so handlers know which player sent the action.
    if (typeof window['_mpApply_' + action] === 'function') {
      window['_mpApply_' + action]({ ...payload, _fromPlayerId: playerId });
      renderAll();
    }
  },

  // ── period commit status ─────────────────────────────────────────
  renderStatus() {
    if (this.mode !== 'live') return;
    const bar = document.getElementById('mp-statusbar');
    if (!bar) return;
    if (G && G.mpPhase === 'endgame' && !G.continuesBeyondEnd) {
      const btn = document.getElementById('abtn');
      if (btn) {
        btn.disabled = true;
        btn.textContent = '🏆 CAMPAIGN COMPLETE — OPEN FINAL RESULTS';
      }
      bar.style.display = 'block';
      const names = this.players.map(p =>
        `<span style="color:${p.socketId===this.socketId?'var(--amb)':p.connected?'#fff':'var(--mut)'}">${p.name}</span>`
      ).join(' &nbsp;·&nbsp; ');
      document.getElementById('mp-status-players').innerHTML = names;
      document.getElementById('mp-status-commits').textContent = 'Final results pending';
      document.getElementById('mp-status-room').textContent = `ROOM ${this.roomId}`;
      return;
    }
    bar.style.display = 'block';
    const names = this.players.map(p => {
      const obs = G && G._mpBankrupt && G._mpBankrupt[p.playerId];
      const lbl = obs ? `${p.name} (observer)` : p.name;
      const done = obs || this.commitLog[p.socketId];
      return `<span style="color:${p.socketId===this.socketId?'var(--amb)':p.connected?'#fff':'var(--mut)'}">${lbl}${done ? ' ✓' : ''}</span>`;
    }).join(' &nbsp;·&nbsp; ');
    const committed = Object.values(this.commitLog).filter(Boolean).length;
    const total = this.players.filter(p=>p.connected).length;
    document.getElementById('mp-status-players').innerHTML = names;
    document.getElementById('mp-status-commits').textContent = `${committed}/${total} committed`;
    document.getElementById('mp-status-room').textContent = `ROOM ${this.roomId}`;
    // NEXT PERIOD button: only host can advance, only when all committed
    const btn = document.getElementById('abtn');
    if (this.isHost) {
      const totalExpected = this.players.length;
      const connectedPlayers = this.players.filter(p=>p.connected);
      const allConnected = connectedPlayers.length >= Math.min(2, totalExpected);
      const nonHost = this.players.filter(p=>p.connected && p.socketId !== this.socketId);
      const guestsReady = nonHost.every(p=>this.commitLog[p.socketId]);
      const guestCount = nonHost.length;
      const guestCommitted = nonHost.filter(p=>this.commitLog[p.socketId]).length;
      const notYetJoined = this.players.filter(p=>!p.connected && p.socketId !== this.socketId);
      btn.disabled = !guestsReady || !allConnected;
      btn.textContent = !allConnected
        ? `⏳ WAITING FOR ${notYetJoined.map(p=>p.name).join(', ')} TO REJOIN`
        : guestsReady
          ? '▶ ADVANCE PERIOD'
          : `⏳ WAITING ${guestCommitted}/${guestCount}`;
    } else {
      const alreadyCommitted = !!this.commitLog[this.socketId];
      btn.disabled = alreadyCommitted;
      btn.textContent = alreadyCommitted ? '✓ READY — WAITING FOR HOST' : '▶ END TURN';
    }
  },
};


// ══════════════════════════════════════════════════════════════════
// MULTIPLAYER DRAFT SYSTEM
// ══════════════════════════════════════════════════════════════════

// Draft state (client-side mirror of server draft object)
const DRAFT = {
  order: [],        // [socketId, socketId, ...] snake order
  pickIdx: 0,
  picks: {},        // {socketId: [stationId, ...]}
  phase: 'first',   // 'first' | 'second' | 'done'
  G: null,          // the pre-draft market state
};

// Era descriptions for the lobby
const ERA_DESC = {
  '1970': 'Start in 1970 — AM dominates, FM is wide open. Host picks the market in the waiting room. Full 50-year arc.',
  '1978': 'Start in 1978 — FM just passed AM in total audience. Host picks the market next. Lean early years.',
  '1985': 'Start in 1985 — CHR wars peak, AM fading fast. Host picks the market next. Harder opening.',
};

function mpPickEra(era) {
  document.getElementById('mp-era').value = era;
  document.getElementById('mp-era-desc').textContent = ERA_DESC[era] || '';
  ['1970','1978','1985'].forEach(e => {
    const btn = document.getElementById('mp-era-' + e);
    if (btn) btn.className = e === era ? 'abt mp-era-on' : 'abt';
  });
}

// ── DIFFICULTY RATING ─────────────────────────────────────────────
function stationDifficulty(s) {
  const share = s.rat?.share || 0;
  if (share > 0.10) return { stars: 1, label: '★ EASY',   color: 'var(--grn)' };
  if (share > 0.05) return { stars: 2, label: '★★ MED',   color: 'var(--amb)' };
  if (share > 0.02) return { stars: 3, label: '★★★ HARD', color: '#f87171' };
  return              { stars: 3, label: '★★★ HARD', color: '#f87171' };
}

/** Multiplayer draft: ★★★ HARD (tier 3) is OK as a second gamble, not as a player’s only first pick. */
function mpDraftStationIsWeak(s) {
  return stationDifficulty(s).stars === 3;
}

/** Every player must have at least one ★ EASY or ★★ MED (not weak-only portfolio). */
function mpDraftEveryPlayerHasAnchorStation() {
  if (!G || !MP.players || !DRAFT.picks) return false;
  for (const p of MP.players) {
    const ids = DRAFT.picks[p.socketId] || [];
    const stns = ids.map(id => G.stations.find(st => st.id === id)).filter(Boolean);
    if (!stns.length) return false;
    if (!stns.some(st => !mpDraftStationIsWeak(st))) return false;
  }
  return true;
}

// VP underdog bonus based on difficulty
function underdogVP(s) {
  const d = stationDifficulty(s);
  return d.stars === 1 ? 0 : d.stars === 2 ? 2 : 5;
}

// ── STARTING CASH PER ERA ─────────────────────────────────────────
const DRAFT_CASH = { '1970': 800000, '1978': 1200000, '1985': 2000000 };

// ── STATION MARKET VALUE (for 2nd station purchase cost) ──────────
function draftStationPrice(s) {
  const annualRev = (s.fin?.rev || 50000) * 2;
  const multiple = s.sig?.type === 'FM' ? 9 : 6;
  return Math.round(annualRev * multiple / 50000) * 50000;
}

/** Cash each player must keep after buying a 2nd station in MP draft — avoids starting $500K–$2M underwater. */
function mpDraftLiquidityReserve(startCash) {
  return Math.max(125000, Math.round(startCash * 0.15));
}

/**
 * Actual 2nd-pick charge in MP: same valuation as draftStationPrice but capped so
 * (startingCash - price) >= mpDraftLiquidityReserve(startingCash).
 */
function mpDraftSecondPickPrice(s, startCash) {
  const raw = draftStationPrice(s);
  const cap = Math.max(0, startCash - mpDraftLiquidityReserve(startCash));
  return Math.min(raw, cap);
}

// ── OPEN DRAFT SCREEN ─────────────────────────────────────────────
function mpOpenDraft(draftData, players, era) {
  Object.assign(DRAFT, draftData);
  DRAFT.G = G; // G is already set from draft_started event

  document.getElementById('mp-draft').style.display = 'block';
  document.getElementById('mp-lobby').style.display = 'none';

  const cash = DRAFT_CASH[era] || 800000;
  const _city =
    (typeof G !== 'undefined' && G && (MARKETS[G.marketId] && MARKETS[G.marketId].label)) ||
    (typeof G !== 'undefined' && G && G.city) ||
    'Market';
  document.getElementById('draft-subtitle').textContent =
    `${era} ${_city.toUpperCase()}  ·  ${players.length} PLAYERS  ·  SNAKE DRAFT  ·  STARTING CASH ${f$(cash)} (1st station free · 2nd capped so you stay solvent)`;
  document.getElementById('draft-cash-show').textContent = f$(cash);

  const hint = document.getElementById('draft-fairness-hint');
  if (hint) {
    hint.style.display = 'block';
    hint.innerHTML =
      '<span style="color:var(--amb)">Draft tip:</span> Your <strong style="color:var(--off)">first</strong> pick must be a viable anchor — <strong style="color:var(--grn)">★ EASY</strong> or <strong style="color:var(--amb)">★★ MED</strong>. ' +
      '<strong style="color:#f87171">★★★ HARD</strong> stations are still in the pool — best as a <em>second</em> station gamble or turnaround, not your only starter.';
  }

  mpRenderDraft(players, era);
}

// ── RENDER DRAFT STATE ────────────────────────────────────────────
function mpRenderDraft(players, era) {
  const draft = DRAFT;
  const draftStartCash = DRAFT_CASH[era] || 800000;
  const mySocketId = MP.socketId;
  const currentPicker = draft.order[draft.pickIdx];
  const isMyTurn = currentPicker === mySocketId;
  const isDone = draft.pickIdx >= draft.order.length || draft.phase === 'done';

  // ── Order strip ───────────────────────────────────────────────
  const orderStrip = document.getElementById('draft-order-strip');
  if (orderStrip) {
    orderStrip.innerHTML = draft.order.map((sid, i) => {
      const p = players.find(pl => pl.socketId === sid);
      const isPast = i < draft.pickIdx;
      const isCurrent = i === draft.pickIdx && !isDone;
      return `<div style="padding:4px 10px;font-size:14px;letter-spacing:1px;
        background:${isCurrent?'var(--amb)':isPast?'#1a1a1a':'#111'};
        color:${isCurrent?'#000':isPast?'#444':'var(--mut)'};
        border:1px solid ${isCurrent?'var(--amb)':'#222'};white-space:nowrap">
        ${p?.name || '?'}${i >= draft.order.length/2 ? ' ②' : ' ①'}
      </div>`;
    }).join('');
  }

  // ── Banner ────────────────────────────────────────────────────
  const banner = document.getElementById('draft-banner-text');
  if (isDone) {
    banner.innerHTML = `<span style="color:var(--grn)">✓ Draft complete.</span> ${MP.isHost ? 'Click START GAME below to begin.' : 'Waiting for host to start the game…'}`;
  } else {
    const pickerPlayer = players.find(p => p.socketId === currentPicker);
    const roundLabel = draft.pickIdx < players.length ? 'ROUND 1' : 'ROUND 2 (optional 2nd station)';
    banner.innerHTML = isMyTurn
      ? `<span style="color:var(--amb)">YOUR PICK</span> — ${roundLabel}. Click a station below.`
      : `<span style="color:var(--mut)">${pickerPlayer?.name || '?'} is picking… (${roundLabel})</span>`;
  }

  // ── Station cards ─────────────────────────────────────────────
  const allPicked = Object.values(draft.picks).flat();
  const playerStations = G ? G.stations.filter(s => s&&!s._bpSlotDeferred&&!s.isPublic) : [];

  const cards = document.getElementById('draft-cards');
  if (cards) {
    cards.innerHTML = playerStations.map(s => {
      const pickedBy = players.find(p => (draft.picks[p.socketId]||[]).includes(s.id));
      const isPicked = !!pickedBy;
      const isMyStation = (draft.picks[mySocketId]||[]).includes(s.id);
      // In round 2, can only pick if I haven't already passed or picked
      const myPickCount = (draft.picks[mySocketId]||[]).length;
      const weakFirstPickBlocked = isMyTurn && myPickCount === 0 && mpDraftStationIsWeak(s);
      const canPick = isMyTurn && !isPicked && !isDone &&
        (draft.pickIdx < draft.order.length) && !weakFirstPickBlocked;
      const isRound2 = draft.pickIdx >= players.length;
      // Enforce 1 AM + 1 FM max: check what sig types I've already picked
      const myPickedStations = (draft.picks[mySocketId]||[]).map(id => playerStations.find(st=>st.id===id)).filter(Boolean);
      const myAMCount = myPickedStations.filter(st => st.sig?.type==='AM').length;
      const myFMCount = myPickedStations.filter(st => st.sig?.type==='FM').length;
      const thisSigType = s.sig?.type === 'FM' ? 'FM' : 'AM';
      const wouldExceedSigLimit = (thisSigType==='AM' && myAMCount>=1) || (thisSigType==='FM' && myFMCount>=1);
      const canPickRound2 = isRound2 && myPickCount < 2 && !isPicked && !wouldExceedSigLimit;

      const diff = stationDifficulty(s);
      const vp = underdogVP(s);
      const rawPrice = draftStationPrice(s);
      const price = mpDraftSecondPickPrice(s, draftStartCash);
      const priceCapped = rawPrice > price;
      const share = ((s.rat?.share || 0) * 100).toFixed(1);
      const fmt = fmtLabel(s.format);

      return `<div onclick="${canPick || canPickRound2 ? `mpDraftPick('${s.id}')` : ''}"
        style="background:${isMyStation?'rgba(245,166,35,.08)':isPicked?'rgba(255,255,255,.03)':'#111'};
               border:1px solid ${isMyStation?'var(--amb)':isPicked?'#1a1a1a':'#2a2a2a'};
               padding:16px;border-radius:2px;cursor:${canPick||canPickRound2?'pointer':'default'};
               opacity:${isPicked&&!isMyStation?'.45':weakFirstPickBlocked&&!isPicked?'.5':'1'};
               transition:border-color .15s,background .15s;
               ${canPick||canPickRound2?'hover:border-color:var(--amb)':''}"
        onmouseover="if(${canPick||canPickRound2})this.style.borderColor='var(--amb)'"
        onmouseout="if(${canPick||canPickRound2})this.style.borderColor='#2a2a2a'">

        <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:8px">
          <div>
            <div style="font-size:16px;color:${isMyStation?'var(--amb)':'#fff'};letter-spacing:1px">${s.callLetters}</div>
            <div style="font-size:14px;color:var(--mut)">${s.sig?.type} · ${signalPowerDisplayLabel(s.sig?.pw)} · ${(s.str||'').toUpperCase()}</div>
          </div>
          <div style="text-align:right">
            <div style="font-size:14px;color:${diff.color}">${diff.label}</div>
            ${vp > 0 ? `<div style="font-size:14px;color:var(--grn)">+${vp} VP bonus</div>` : ''}
          </div>
        </div>

        <div style="font-size:14px;color:var(--off);margin-bottom:6px">${fmt}</div>
        <div style="font-size:15px;color:var(--mut);margin-bottom:2px">${share}% share · ${f$(s.fin?.rev||0)}/period</div>
        <div style="font-size:14px;color:#444">2nd station: ${f$(price)}${priceCapped ? ` <span style="color:var(--mut);font-size:12px">(draft cap · book ${f$(rawPrice)})</span>` : ''}</div>

        ${isPicked ? `<div style="margin-top:8px;font-size:14px;color:${isMyStation?'var(--amb)':'var(--mut)'};letter-spacing:1px">
          ${isMyStation ? '✓ YOUR STATION' : `PICKED BY ${pickedBy?.name?.toUpperCase()}`}</div>` : ''}
        ${weakFirstPickBlocked && !isPicked ? `<div style="margin-top:8px;font-size:12px;color:#f87171;line-height:1.4">First pick: choose ★ EASY or ★★ MED as your anchor. ★★★ HARD opens up for your second pick.</div>` : ''}
        ${canPick ? `<div style="margin-top:8px;font-size:14px;color:var(--amb);letter-spacing:1px">▶ CLICK TO PICK</div>` : ''}
        ${canPickRound2 ? `<div style="margin-top:8px;font-size:14px;color:var(--amb);letter-spacing:1px">▶ BUY FOR ${f$(price)}</div>` : ''}
        ${isRound2 && !isPicked && !isMyStation && wouldExceedSigLimit ? `<div style="margin-top:8px;font-size:14px;color:var(--mut);letter-spacing:1px">— ALREADY HAVE ${thisSigType}</div>` : ''}
      </div>`;
    }).join('');
  }

  // ── Second station pass button ─────────────────────────────────
  const secondWrap = document.getElementById('draft-second-wrap');
  if (secondWrap) {
    const isMyRound2 = currentPicker === mySocketId &&
      draft.pickIdx >= players.length &&
      draft.pickIdx < draft.order.length;
    secondWrap.style.display = isMyRound2 ? 'block' : 'none';
  }

  // ── Draft log ─────────────────────────────────────────────────
  // (appended separately in mpDraftPickMade)

  // ── Host: show start button when done ─────────────────────────
  if (isDone && MP.isHost) {
    const banner = document.getElementById('draft-banner');
    if (banner && !document.getElementById('draft-start-btn')) {
      const btn = document.createElement('button');
      btn.id = 'draft-start-btn';
      btn.className = 'abt g';
      btn.style = 'margin-top:12px;padding:12px 32px;font-size:15px;width:100%';
      btn.textContent = '▶ START GAME';
      btn.onclick = mpDraftFinalize;
      banner.appendChild(btn);
    }
  }
}

// ── MAKE A PICK ───────────────────────────────────────────────────
function mpDraftPick(stationId) {
  if (!MP.socket) return;
  MP.socket.emit('draft_pick', { roomId: MP.roomId, stationId });
}

function mpDraftPass() {
  if (!MP.socket) return;
  MP.socket.emit('draft_pass', { roomId: MP.roomId });
}

// ── RECEIVE A PICK (from server broadcast) ────────────────────────
function mpDraftPickMade({ socketId, playerId, playerName, stationId, draft }) {
  Object.assign(DRAFT, draft);
  const players = MP.players;
  const era = document.getElementById('mp-era')?.value || '1970';

  // Update log
  const log = document.getElementById('draft-log');
  if (log) {
    const s = stationId ? G.stations.find(st => st.id === stationId) : null;
    const entry = stationId
      ? `<div><span style="color:var(--amb)">${playerName}</span> picks <strong style="color:#fff">${s?.callLetters || stationId}</strong> (${s?.format?fmtLabel(s.format):'?'})</div>`
      : `<div style="color:var(--mut)">${playerName} passes on a second station.</div>`;
    log.innerHTML += entry;
    log.scrollTop = log.scrollHeight;
  }

  mpRenderDraft(players, era);
}

// ── FINALIZE DRAFT (host only) ────────────────────────────────────
function mpDraftFinalize() {
  if (!MP.isHost || !MP.socket) return;
  const players = MP.players;
  const era = document.getElementById('mp-era')?.value || '1970';
  const cash = DRAFT_CASH[era] || 800000;

  if (!mpDraftEveryPlayerHasAnchorStation()) {
    showToast(
      'Each player needs at least one ★ EASY or ★★ MED anchor. ★★★ HARD-only starts are not allowed — pick a stronger first station.',
      'warn'
    );
    return;
  }

  // Apply picks to G: mark stations as player-owned
  players.forEach(p => {
    const stationIds = DRAFT.picks[p.socketId] || [];
    stationIds.forEach((sid, idx) => {
      const s = G.stations.find(st => st.id === sid);
      if (!s) return;
      s.isPlayer = true;
      s._mpOwner = p.playerId;  // which player owns this station
      s.color = ['#f5a623','#60a5fa','#34d399','#f87171'][p.playerId % 4];
      applyDefaultBrandToPlayerStation(s);
      // Set player-specific cash (first station free, second costs market rate)
      if (idx === 0) {
        if (!G._playerCash) G._playerCash = {};
        G._playerCash[p.playerId] = cash;
        // Record each player's actual starting cash for scoreCalc baseline
        if (!G._draftStartCash) G._draftStartCash = {};
        G._draftStartCash[p.playerId] = cash;
      } else {
        // Deduct 2nd station cost from their cash (capped — raw valuation can exceed starting pool)
        const price = mpDraftSecondPickPrice(s, cash);
        if (!G._playerCash) G._playerCash = {};
        G._playerCash[p.playerId] = (G._playerCash[p.playerId] || cash) - price;
        if (!G._draftStartCash) G._draftStartCash = {};
        G._draftStartCash[p.playerId] = G._playerCash[p.playerId];
      }
      // Apply underdog VP bonus
      const vp = underdogVP(s);
      if (vp > 0) {
        if (!G._underdogVP) G._underdogVP = {};
        G._underdogVP[p.playerId] = (G._underdogVP[p.playerId] || 0) + vp;
      }
    });
  });

  // For the host (player 0), set G.cash to their starting amount
  const hostStations = DRAFT.picks[MP.socketId] || [];
  G.cash = G._playerCash?.[0] || cash;
  G.ps = G.stations.filter(s => s.isPlayer);

  // Each player will set their own G.cash when they receive game_started
  // Store _playerCash in G so guests can read it
  migrateSave(G);

  MP.socket.emit('draft_complete', { roomId: MP.roomId, G });
}

// ── MP HELPER: this player's stations only ──────────────────────
function myPS() {
  if (!G || !G.ps) return [];
  if (MP.mode !== 'live') return G.ps;
  return G.ps.filter(s => s._mpOwner === MP.playerId);
}
/** Multiplayer: cash wallet for this client — never use raw G.cash for display without this in MP. */
function mpMyCashOnHand() {
  if (MP.mode !== 'live' || !G) return G?.cash ?? 0;
  const w = G._playerCash?.[MP.playerId];
  return w !== undefined && w !== null ? w : (G.cash ?? 0);
}
/** Solo or MP: adjust this player's cash and sync MP wallet display. */
function wlAdjustMyCash(delta) {
  const d = Math.round(delta);
  if (!d || !G) return;
  if (MP.mode === 'live') {
    if (!G._playerCash) G._playerCash = {};
    const pid = MP.playerId;
    G._playerCash[pid] = (G._playerCash[pid] || 0) + d;
    if (MP.playerId === pid) G.cash = G._playerCash[pid];
    MP.emit('player_cash_update', { playerId: pid, cash: G._playerCash[pid] });
  } else {
    G.cash = (G.cash || 0) + d;
  }
}
/** Forced / distress sale: floor so low-revenue stations are not sold for trivial cash. */
function distressSaleProceeds(s) {
  if (!s) return 150000;
  const rev = s.fin?.rev || 0;
  const fromRecentRev = Math.round(rev * 6);
  let listApprox = 0;
  try {
    listApprox = typeof draftStationPrice === 'function' ? draftStationPrice(s) : Math.round((rev * 2) * 6 * 50000);
  } catch (e) {
    listApprox = Math.round(rev * 120);
  }
  return Math.max(fromRecentRev, Math.round(listApprox * 0.22), 150000);
}

/** True if `fmt` can air on this facility (AM main vs FM / translator). */
function formatPlausibleOnFacility(s, fmt) {
  const m = FM[fmt];
  if (!m || m.public) return false;
  const amMain = s.sig?.type === 'AM' && !s.fmBooster;
  if (amMain && m.fm) return false;
  return true;
}
/** New format for a station sold to an independent buyer — different from current when possible. */
function pickAiDistressResaleFormat(G, s) {
  const y = G.year || 1970;
  const cur = s.format;
  const pool = [];
  const tryAdd = (f) => {
    if (!f || f === cur || pool.includes(f)) return;
    if (!FM[f] || FM[f].public) return;
    if (!formatAllowedInMarket(f, G.marketId, y)) return;
    if (!formatUnlockedForYear(f, G)) return;
    if (!formatPlausibleOnFacility(s, f)) return;
    pool.push(f);
  };
  (FADJ[cur] || []).forEach(tryAdd);
  Object.keys(FM).forEach(tryAdd);
  return pool.length ? pick(pool) : cur;
}
/**
 * After a distress / forced sale the license stays in the sim but new operators rebrand:
 * new call letters, new format (when rules allow), fresh brand — avoids “ghost” of the old player on the dial.
 */
function aiRebrandStationAfterDistressSale(G, s) {
  if (!s || s._bpSlotDeferred || s.isPublic) return;
  const oldCall = s.callLetters;
  const oldFmt = s.format;
  const oldFmtLbl = fmtLabel(oldFmt);
  if (UC && typeof UC.delete === 'function' && UC.has(oldCall)) UC.delete(oldCall);
  const _savedMarket = ACTIVE_MARKET;
  ACTIVE_MARKET = G.marketId || ACTIVE_MARKET;
  try {
    s.callLetters = gc();
  } finally {
    ACTIVE_MARKET = _savedMarket;
  }
  const nf = pickAiDistressResaleFormat(G, s);
  const adj = FADJ[oldFmt]?.includes(nf);
  const pen = adj ? 0.3 : 0.42;
  s.format = nf;
  s.brand = gbBrandForStationReplace(s, nf);
  s._formatAge = 0;
  s.identity = 0;
  s._identityPeak = 0;
  s.identityBudget = 0;
  const _talkFmts = ['NEWS_TALK', 'SPORTS_TALK', 'PODCAST_TALK', 'ALL_NEWS'];
  s.ops.sell = _talkFmts.includes(nf) ? 0.6 : 0.55;
  if (s.drift && typeof s.drift === 'object') Object.keys(s.drift).forEach((k) => delete s.drift[k]);
  if (s.driftHistory && typeof s.driftHistory === 'object') Object.keys(s.driftHistory).forEach((k) => delete s.driftHistory[k]);
  delete s.cosmeticLogoUrl;
  delete s.cosmeticLogoV;
  delete s.cosmeticLogoTone;
  delete s.cosmeticRemoteVanUrl;
  delete s.cosmeticRemoteVanV;
  delete s.remoteVanMarketingLift;
  delete s.heritageIncumbent;
  delete s._simulcastSource;
  Object.values(s.prog).forEach((sd) => {
    if (sd) sd.quality = Math.round(Math.max(10, (sd.quality || 40) * (1 - pen)));
  });
  Object.entries(s.prog).forEach(([, sd]) => {
    if (sd?.talent && Math.random() < 0.38) {
      sd.talent = null;
      sd.quality = Math.round(Math.max(10, (sd.quality || 30) * 0.62));
    }
  });
  s.oq = Math.round(Object.entries(SW).reduce((sum, [sl, w]) => sum + effSlotQForOq(s.prog[sl]) * w, 0));
  COH.forEach((c) => {
    if (s.mom[c]) s.mom[c].cur = Math.max(0.002, s.mom[c].cur * (1 - pen * 0.45));
  });
  if (!Array.isArray(s.flog)) s.flog = [];
  s.flog.push({ from: oldFmt, to: nf, _distress: true });
  logHistory(s, 'CALLSIGN', `New owner: ${oldCall} → ${s.callLetters} (distress sale)`, G);
  if (nf !== oldFmt) logHistory(s, 'FORMAT', `Under new ownership: ${oldFmtLbl} → ${fmtLabel(nf)}`, G);
  calcRev(s, G);
  recalc(G.stations, G);
}

/**
 * Host state_broadcast replaces all of G — guest-generated portrait/logo URLs (fetched on the
 * guest client) would be lost. Copy those cosmetic fields from the previous snapshot onto the
 * new G for matching station / talent ids so guests keep art across period advances.
 */
function mergeCosmeticPreserve(prevG, nextG) {
  if (!prevG || !nextG || !Array.isArray(prevG.stations) || !Array.isArray(nextG.stations)) return;
  const prevById = Object.fromEntries(prevG.stations.filter(Boolean).map(s => [s.id, s]));
  const slotKeys = typeof SL !== 'undefined' && SL ? Object.keys(SL) : [];
  function sameTalent(pt, st) {
    if (!pt || !st) return false;
    if (pt.id && st.id && pt.id === st.id) return true;
    return (
      normTalentNameKey(pt.name || '') === normTalentNameKey(st.name || '') &&
      (pt._hireYear ?? pt._careerStartYear ?? -1) === (st._hireYear ?? st._careerStartYear ?? -1)
    );
  }
  for (const s of nextG.stations) {
    if (!s || !prevById[s.id]) continue;
    const p = prevById[s.id];
    if (p.cosmeticLogoUrl && !s.cosmeticLogoUrl) {
      s.cosmeticLogoUrl = p.cosmeticLogoUrl;
      if (p.cosmeticLogoV != null) s.cosmeticLogoV = p.cosmeticLogoV;
    }
    if (p.cosmeticLogoTone && !s.cosmeticLogoTone) s.cosmeticLogoTone = p.cosmeticLogoTone;
    if (p.cosmeticRemoteVanUrl && !s.cosmeticRemoteVanUrl) {
      s.cosmeticRemoteVanUrl = p.cosmeticRemoteVanUrl;
      if (p.cosmeticRemoteVanV != null) s.cosmeticRemoteVanV = p.cosmeticRemoteVanV;
    }
    if (p.remoteVanMarketingLift != null && s.remoteVanMarketingLift == null) {
      s.remoteVanMarketingLift = p.remoteVanMarketingLift;
    }
    if (p.remoteVanPurchasedYear != null && s.remoteVanPurchasedYear == null) {
      s.remoteVanPurchasedYear = p.remoteVanPurchasedYear;
    }
    if (p.prog && s.prog && slotKeys.length) {
      for (const slot of slotKeys) {
        const pt = p.prog[slot] && p.prog[slot].talent;
        const st = s.prog[slot] && s.prog[slot].talent;
        if (!pt || !st || !sameTalent(pt, st)) continue;
        if (pt._portraitUrl && !st._portraitUrl) {
          st._portraitUrl = pt._portraitUrl;
          if (pt._portraitV != null) st._portraitV = pt._portraitV;
          if (pt._portraitLibraryAsset && !st._portraitLibraryAsset) st._portraitLibraryAsset = pt._portraitLibraryAsset;
        }
      }
    }
  }
  const prevBench = prevG.talentBench || [];
  const nextBench = nextG.talentBench || [];
  if (prevBench.length && nextBench.length) {
    const prevTalById = new Map();
    prevBench.forEach(ent => {
      const t = ent && ent.talent;
      if (t && t.id) prevTalById.set(t.id, t);
    });
    nextBench.forEach(ent => {
      const t = ent && ent.talent;
      if (!t || !t.id) return;
      const pt = prevTalById.get(t.id);
      if (pt && pt._portraitUrl && !t._portraitUrl) {
        t._portraitUrl = pt._portraitUrl;
        if (pt._portraitV != null) t._portraitV = pt._portraitV;
        if (pt._portraitLibraryAsset && !t._portraitLibraryAsset) t._portraitLibraryAsset = pt._portraitLibraryAsset;
      }
    });
  }
}

// ── NEXT PERIOD ROUTER ────────────────────────────────────────────
// Solo: just run advTurn()
// MP host: run advTurn() (only when all players committed — button is gated)
// MP guest: commit to server, wait for host to advance
function mpHandleNextPeriod() {
  if (MP.mode === 'solo') {
    advTurn();
  } else {
    // Both host and guest commit the same way
    // Server fires run_advturn to host once everyone committed
    mpCommit();
  }
}

