/** Origin of the Node game server (Socket.io + /api + /generated-*). Set from VITE_GAME_SERVER_URL in main.js; else current page origin (Vite proxy or single-host deploy). */
function wlGameServerOrigin(){
  try{
    const u=typeof window!=='undefined'&&window.__WL_GAME_SERVER_URL&&String(window.__WL_GAME_SERVER_URL).trim();
    if(u)return String(u).replace(/\/$/,'');
  }catch(_e){}
  try{
    const m=typeof document!=='undefined'&&document.querySelector('meta[name="wl-game-server-url"]')?.getAttribute('content')?.trim();
    if(m)return String(m).replace(/\/$/,'');
  }catch(_e){}
  if(typeof location!=='undefined'&&location.origin)return location.origin;
  return '';
}
/** Absolute URL for game API routes (e.g. /api/generate-logo). */
function wlGameApiUrl(path){
  const p=path.startsWith('/')?path:'/'+path;
  return wlGameServerOrigin()+p;
}
/** Absolute URL for <img> / download when stored paths are /generated-* and the API lives on another host. */
function wlGameMediaAbsUrl(pathOrUrlWithQuery){
  if(pathOrUrlWithQuery==null||pathOrUrlWithQuery==='')return pathOrUrlWithQuery;
  const s=String(pathOrUrlWithQuery);
  if(/^https?:\/\//i.test(s))return s;
  const qIdx=s.indexOf('?');
  const pathOnly=qIdx>=0?s.slice(0,qIdx):s;
  const qs=qIdx>=0?s.slice(qIdx):'';
  const origin=wlGameServerOrigin();
  if(pathOnly.startsWith('/generated-logos/')||pathOnly.startsWith('/generated-portraits/')||pathOnly.startsWith('/generated-remote-vans/'))return origin+pathOnly+qs;
  return pathOnly.startsWith('/')?pathOnly+qs:s;
}

// ── Clerk (optional) — meta wl-clerk-publishable-key + server CLERK_SECRET_KEY ──
function wlClerkPublishableKey(){
  try {
    return document.querySelector('meta[name="wl-clerk-publishable-key"]')?.getAttribute('content')?.trim() || '';
  } catch(e) { return ''; }
}
function wlLoadClerkScript(){
  if (window.__wlClerkScriptPromise) return window.__wlClerkScriptPromise;
  const pk = wlClerkPublishableKey();
  if (!pk) {
    window.__wlClerkScriptPromise = Promise.resolve(null);
    return window.__wlClerkScriptPromise;
  }
  // Pre-initialized by Vite src/main.js (@clerk/clerk-js + UI bundle)
  if (window.__wlClerkLoaded && window.Clerk) {
    window.__wlClerkScriptPromise = Promise.resolve(pk);
    return window.__wlClerkScriptPromise;
  }
  window.__wlClerkScriptPromise = new Promise((resolve, reject) => {
    if (window.Clerk) return resolve(pk);
    const s = document.createElement('script');
    s.src = 'https://cdn.jsdelivr.net/npm/@clerk/clerk-js@5/dist/clerk.browser.js';
    s.async = true;
    s.onload = () => resolve(pk);
    s.onerror = () => reject(new Error('Failed to load Clerk'));
    document.head.appendChild(s);
  });
  return window.__wlClerkScriptPromise;
}
async function wlGetClerkToken(){
  const pk = wlClerkPublishableKey();
  if (!pk) return null;
  try {
    await wlLoadClerkScript();
    const Clerk = window.Clerk;
    if (!Clerk) return null;
    if (!window.__wlClerkLoaded) {
      await Clerk.load({ publishableKey: pk });
      window.__wlClerkLoaded = true;
    }
    wlMpRefreshAuthBar();
    const sess = Clerk.session;
    if (!sess) return null;
    return await sess.getToken();
  } catch(e) {
    console.warn('[Clerk]', e);
    return null;
  }
}
function wlMpRefreshAuthBar(){
  const wrap = document.getElementById('wl-mp-auth');
  if (!wrap) return;
  const pk = wlClerkPublishableKey();
  if (!pk) { wrap.style.display = 'none'; return; }
  wrap.style.display = 'block';
  if (typeof window.wlRemountClerkLobby === 'function') {
    window.wlRemountClerkLobby();
    return;
  }
  const st = document.getElementById('wl-mp-auth-status');
  const btn = document.getElementById('wl-mp-auth-btn');
  if (!st || !btn) return;
  const Clerk = window.Clerk;
  if (!window.__wlClerkLoaded || !Clerk?.session) {
    st.textContent = 'Not signed in';
    btn.style.display = 'inline-block';
    btn.textContent = 'Sign in';
    return;
  }
  const u = Clerk.user;
  const label = u?.primaryEmailAddress?.emailAddress || u?.username || (u?.firstName ? u.firstName + ' ' + (u.lastName || '') : '') || 'Signed in';
  st.textContent = label.trim() || 'Signed in';
  btn.style.display = 'inline-block';
  btn.textContent = 'Sign out';
}
async function wlMpAuthAction(){
  const pk = wlClerkPublishableKey();
  if (!pk) return;
  try {
    await wlLoadClerkScript();
    const Clerk = window.Clerk;
    if (!window.__wlClerkLoaded) {
      await Clerk.load({ publishableKey: pk });
      window.__wlClerkLoaded = true;
    }
    if (Clerk.session) {
      await Clerk.signOut();
    } else {
      const after = `${typeof location !== 'undefined' ? location.origin : ''}/play.html`;
      Clerk.openSignIn({ forceRedirectUrl: after, fallbackRedirectUrl: after });
    }
    setTimeout(() => wlMpRefreshAuthBar(), 600);
  } catch(e) {
    showToast(String(e.message || e), 'warn');
  }
}

