window._mpApply_fmbooster = function({ sid }) {
  // Apply the same station mutations that doFmBooster does on the host
  const s = G.stations.find(st=>st.id===sid);
  if(s && s.sig.type==='AM' && !s.fmBooster){
    s.fmBooster = true;
    s._boosterOrigSig = {type:s.sig.type, pw:s.sig.pw, reach:s.sig.reach, universe:s.sig.universe};
    s.sig.type = 'FM';
    s.sig.pw = 'translator';
    // Pick an FM frequency not already in use
    const fmFreqs=['92.3 FM','93.7 FM','96.9 FM','98.3 FM','101.1 FM','105.3 FM','106.7 FM'];
    const usedFm=G.stations.map(st=>st.freq||st._deferFreq).filter(Boolean);
    const newFm=fmFreqs.find(f=>!usedFm.includes(f))||'107.9 FM';
    s._boosterOrigFreq=s.freq;
    s.freq=newFm;
    if(s.isPlayer)applyDefaultBrandToPlayerStation(s);
  }
  renderAll();
};
window._mpApply_migrate = function({ amId, fmId }) {
  applyFmSimulcastMigration(amId, fmId);
};
window._mpApply_acq = function({ sid, playerId, color }) {
  const s = G.stations.find(st=>st.id===sid); if(!s) return;
  s.isPlayer=true;
  s._mpOwner = playerId;
  s.color = color || ['#f5a623','#60a5fa','#34d399','#f87171'][(playerId||0)%4];
  // Clear corp ownership if any
  s.corpOwner=null; s.corpName=null; s.corpColor=null;
  applyDefaultBrandToPlayerStation(s);
  G.ps=G.stations.filter(st=>st.isPlayer); renderAll();
  queueAutoLogosForPlayerStations();
};
window._mpApply_loan = function({ amount, _fromPlayerId }) {
  if(_fromPlayerId === undefined) return;
  if(!G._playerLoans) G._playerLoans = {};
  if(!G._playerLoans[_fromPlayerId]) G._playerLoans[_fromPlayerId] = [];
  const loans = G._playerLoans[_fromPlayerId];
  let f = loans.find(l=>l.kind==='facility'||l.id==='credit');
  if(!f){
    f = { id:'credit', kind:'facility', label:'Line of credit', principal:0, takenYear:G.year, openedYear:G.year, openedPeriod:G.period };
    loans.push(f);
  }
  f.principal = (f.principal||0) + (amount||0);
  f.rateAtLastDraw = effectiveAnnualLoanRate(G, _fromPlayerId);
  if(f.openedYear==null){ f.openedYear=G.year; f.openedPeriod=G.period; }
  if(MP.mode==='live' && amount){
    if(!G._playerCash) G._playerCash = {};
    G._playerCash[_fromPlayerId] = (G._playerCash[_fromPlayerId]||0) + amount;
  }
};
window._mpApply_repay = function({ loanKey, amt, _fromPlayerId }) {
  if(_fromPlayerId === undefined) return;
  if(G._playerLoans?.[_fromPlayerId])
    G._playerLoans[_fromPlayerId] = G._playerLoans[_fromPlayerId].filter(l=>(l.id+'')!==(loanKey+''));
  if(!G._playerCash) G._playerCash = {};
  const pay = amt != null ? amt : 0;
  if(pay) G._playerCash[_fromPlayerId] = (G._playerCash[_fromPlayerId]||0) - pay;
};
window._mpApply_repay_partial = function({ loanKey, amt, remaining, _fromPlayerId }) {
  if(_fromPlayerId === undefined) return;
  const loan = G._playerLoans?.[_fromPlayerId]?.find(l=>(l.id+'')===(loanKey+''));
  if(loan){
    if(typeof remaining === 'number') loan.principal = remaining;
    else if(loan.owed != null) loan.owed = remaining;
  }
  if(!G._playerCash) G._playerCash = {};
  G._playerCash[_fromPlayerId] = (G._playerCash[_fromPlayerId]||0) - (amt||0);
};



